"use client";

import { useEffect, useState } from "react";
import styles from "./page.module.css";

export default function Home() {
  const [theme, setTheme] = useState<"light" | "dark">("light");

  useEffect(() => {
    // Initialization: Check current theme from localStorage/document attribute
    const currentTheme = document.documentElement.getAttribute("data-theme") as "light" | "dark";
    if (currentTheme) setTheme(currentTheme);
  }, []);

  const toggleTheme = () => {
    const newTheme = theme === "light" ? "dark" : "light";
    setTheme(newTheme);
    document.documentElement.setAttribute("data-theme", newTheme);
    localStorage.setItem("theme", newTheme);
  };

  return (
    <div className={styles.page}>
      <header className={styles.header}>
        <div className={styles.logo}>
          <div className={styles.logoIcon}></div>
          <h1>AutoWorkshop MMS</h1>
        </div>
        
        <div className={styles.headerActions}>
          <button className={styles.themeToggle} onClick={toggleTheme}>
            {theme === "light" ? "🌙 Dark Mode" : "☀️ Light Mode"}
          </button>
          
          <div className={styles.userProfile}>
            <div className={styles.avatar}>A</div>
            <span>Admin Kasir</span>
          </div>
        </div>
      </header>

      <div className={styles.mainLayout}>
        <aside className={styles.sidebar}>
          <nav className={styles.nav}>
            <a href="#" className={`${styles.navItem} ${styles.active}`}>📊 Dashboard</a>
            <a href="#" className={styles.navItem}>🛒 POS / Kasir</a>
            <a href="#" className={styles.navItem}>📦 Inventaris</a>
            <a href="#" className={styles.navItem}>👥 Pelanggan</a>
            <a href="#" className={styles.navItem}>👨‍🔧 Mekanik</a>
            <a href="#" className={styles.navItem}>💰 Keuangan</a>
            <div className={styles.navDivider}></div>
            <a href="#" className={styles.navItem}>⚙️ Pengaturan</a>
          </nav>
        </aside>

        <main className={styles.content}>
          <div className={styles.dashboardHeader}>
            <h2>Dashboard Overview</h2>
            <p>Welcome to modern glassmorphism dashboard preview.</p>
          </div>

          <div className={styles.statsGrid}>
            <div className={styles.statCard}>
              <div className={styles.statIcon} style={{ background: 'var(--status-info)' }}>💰</div>
              <div>
                <h3>Pendapatan Hari Ini</h3>
                <p className={styles.statValue}>Rp 4.500.000</p>
              </div>
            </div>
            
            <div className={styles.statCard}>
              <div className={styles.statIcon} style={{ background: 'var(--status-success)' }}>🚗</div>
              <div>
                <h3>Kendaraan Selesai</h3>
                <p className={styles.statValue}>12 Unit</p>
              </div>
            </div>

            <div className={styles.statCard}>
              <div className={styles.statIcon} style={{ background: 'var(--status-warning)' }}>⚠️</div>
              <div>
                <h3>Peringatan Stok</h3>
                <p className={styles.statValue}>5 Item</p>
              </div>
            </div>
          </div>
          
          <div className={styles.contentArea}>
            <div className={styles.card}>
              <h3>Testing Global Design Tokens</h3>
              <p>Tombol, warna latar belakang, dan card ini mengonsumsi custom variables CSS `var(--bg-surface)` dan lainnya. Coba <strong>tekan tombol Theme Toggle</strong> di pojok kanan atas untuk melihat perubahan yang dinamis!</p>
              
              <div className={styles.actionButtons}>
                <button className={styles.btnPrimary}>Primary Action</button>
                <button className={styles.btnSecondary}>Secondary</button>
                <button className={styles.btnDanger}>Hapus Data</button>
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
}
